// src/components/layouts/TechnicianLayout.jsx

import { useState } from "react";

import TechnicianDashboard from "../dashboards/TechnicianDashboard";
import AssignedSystems from "../technician/AssignedSystems";
import InvestigationLogs from "../technician/InvestigationLogs";

export default function TechnicianLayout() {
  const [activeNav, setActiveNav] = useState("dashboard");

  // Dummy technician profile
  const technician = {
    name: "Alex Rodriguez",
    id: "TECH-447",
    shift: "Active",
    avatar: "AR",
  };

  // Decide which page to show
  const renderContent = () => {
    switch (activeNav) {
      case "dashboard":
        return <TechnicianDashboard />;
      case "assigned":
        return <AssignedSystems />;
      case "logs":
        return <InvestigationLogs />;
      default:
        return <TechnicianDashboard />;
    }
  };

  return (
    <div className="flex h-screen bg-gray-50">

      {/* ================= SIDEBAR ================= */}
      <aside className="w-72 bg-gray-900 text-white flex flex-col">
        <div className="p-6 border-b border-gray-700">
          <h1 className="text-xl font-bold">MaintenanceAI</h1>
          <p className="text-xs text-gray-400">Technician Portal</p>
        </div>

        <nav className="flex-1 p-3 space-y-2">
          <NavItem
            icon="📊"
            label="Dashboard"
            active={activeNav === "dashboard"}
            onClick={() => setActiveNav("dashboard")}
          />
          <NavItem
            icon="💻"
            label="Assigned Systems"
            active={activeNav === "assigned"}
            onClick={() => setActiveNav("assigned")}
          />
          <NavItem
            icon="📝"
            label="Investigation Logs"
            active={activeNav === "logs"}
            onClick={() => setActiveNav("logs")}
          />
        </nav>

        <div className="p-4 border-t border-gray-700 text-xs text-gray-400">
          Logged in as {technician.id}
        </div>
      </aside>

      {/* ================= MAIN ================= */}
      <div className="flex-1 flex flex-col">

        {/* HEADER */}
        <header className="bg-white border-b px-6 py-3 flex justify-between items-center">
          <input
            type="text"
            placeholder="Search system ID..."
            className="px-3 py-2 border rounded-md text-sm w-72"
          />

          <div className="flex items-center gap-4">
            <span className="text-sm font-medium text-gray-900">
              {technician.name}
            </span>
            <span className="px-2 py-1 text-xs bg-green-100 text-green-700 rounded">
              {technician.shift}
            </span>
          </div>
        </header>

        {/* CONTENT */}
        <main className="flex-1 overflow-y-auto">
          {renderContent()}
        </main>

        {/* FOOTER */}
        <footer className="bg-white border-t px-6 py-3 text-xs text-gray-500 flex justify-between">
          <span>Agent Connected</span>
          <span>Production · v1.0.0</span>
        </footer>
      </div>
    </div>
  );
}

/* ================= NAV ITEM ================= */
function NavItem({ icon, label, active, onClick }) {
  return (
    <button
      onClick={onClick}
      className={`w-full flex items-center gap-3 px-4 py-3 rounded-md text-sm transition
        ${
          active
            ? "bg-blue-600 text-white"
            : "text-gray-300 hover:bg-gray-700"
        }`}
    >
      <span>{icon}</span>
      <span>{label}</span>
    </button>
  );
}
